import{_ as d,o as r,c as e,ag as a}from"./chunks/framework.Cqf6AMW8.js";const h=JSON.parse('{"title":"STM32 RTC实时时钟","description":"STM32 RTC（实时时钟）的配置和使用。","frontmatter":{"title":"STM32 RTC实时时钟","description":"STM32 RTC（实时时钟）的配置和使用。","date":"2026-04-21T00:00:00.000Z","tags":["STM32","RTC","实时时钟","时钟源"],"sidebar":"auto"},"headers":[],"relativePath":"docs/hardware/stm32/stm32-19-RTC.md","filePath":"docs/hardware/stm32/stm32-19-RTC.md","lastUpdated":1776715536000}'),o={name:"docs/hardware/stm32/stm32-19-RTC.md"};function C(T,t,c,R,_,s){return r(),e("div",null,[...t[0]||(t[0]=[a('<h3 id="rtc-实时时钟" tabindex="-1">RTC（实时时钟） <a class="header-anchor" href="#rtc-实时时钟" aria-label="Permalink to &quot;RTC（实时时钟）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td>主要功能</td><td>独立的定时器，为系统提供时钟和日历功能</td></tr><tr><td>工作区域</td><td>处于备份区域，系统复位时数据不清零</td></tr><tr><td>供电方式</td><td>VDD（2.0-3.6V）正常供电，VDD断电后由VBAT（1.8-3.6V）供电继续走时</td></tr><tr><td>计数器</td><td>32位可编程计数器，对应Unix时间戳的秒计数器</td></tr><tr><td>预分频器</td><td>20位可编程预分频器，可适配不同频率的输入时钟</td></tr><tr><td>时钟源选择</td><td>HSE时钟除以128（通常为8MHz/128）<br>LSE振荡器时钟（通常为32.768KHz）<br>LSI振荡器时钟（40KHz）</td></tr></tbody></table><h3 id="rtc使用方法" tabindex="-1">RTC使用方法 <a class="header-anchor" href="#rtc使用方法" aria-label="Permalink to &quot;RTC使用方法&quot;">​</a></h3><table tabindex="0"><thead><tr><th>操作</th><th>函数</th><th>说明</th></tr></thead><tbody><tr><td>配置RTC时钟源</td><td><code>RCC_RTCCLKConfig(RCC_RTCCLKSource_LSE)</code></td><td>选择LSE作为RTC时钟源</td></tr><tr><td>使能RTC时钟</td><td><code>RCC_RTCCLKCmd(ENABLE)</code></td><td>启动RTC时钟</td></tr><tr><td>等待同步</td><td><code>RTC_WaitForSynchro()</code></td><td>等待RTC寄存器同步</td></tr><tr><td>设置预分频器</td><td><code>RTC_SetPrescaler(32768 - 1)</code></td><td>设置RTC预分频，使计数频率为1Hz</td></tr><tr><td>设置时间</td><td><code>RTC_SetCounter(time_cnt)</code></td><td>将时间戳写入RTC计数器</td></tr><tr><td>读取时间</td><td><code>RTC_GetCounter()</code></td><td>读取当前时间戳</td></tr><tr><td>设置闹钟</td><td><code>RTC_SetAlarm(RTC_Format_BIN, RTC_Alarm_A, &amp;alarm)</code></td><td>配置RTC闹钟</td></tr><tr><td>使能闹钟中断</td><td><code>RTC_ITConfig(RTC_IT_ALRA, ENABLE)</code></td><td>启用RTC闹钟中断</td></tr></tbody></table>',4)])])}const i=d(o,[["render",C]]);export{h as __pageData,i as default};
